  1→// ── Shared WebSocket connection with JSON-RPC handshake and reconnect ──
  2→import { localizeRpcError, nextId, sendRpc } from "./helpers.js";
  3→import { getPreferredLocale } from "./i18n.js";
  4→import * as S from "./state.js";
  5→
  6→var reconnectTimer = null;
  7→var lastOpts = null;
  8→var authRedirectPending = false;
  9→
 10→/** Registry of server-request handlers keyed by method name (v4 bidir RPC). */
 11→var serverRequestHandlers = {};
 12→
 13→function resolveLocale() {
 14→	return getPreferredLocale();
 15→}
 16→
 17→function resetAuthRedirectGuard() {
 18→	authRedirectPending = false;
 19→}
 20→
 21→window.addEventListener("moltis:auth-status-sync-complete", resetAuthRedirectGuard);
 22→
 23→/**
 24→ * Register a handler for server-initiated RPC requests (v4 bidirectional RPC).
 25→ * @param {string} method — method name (e.g. "node.invoke")
 26→ * @param {(params: object) => Promise<object>} handler — returns result or throws
 27→ * @returns {() => void} unregister function
 28→ */
 29→export function onServerRequest(method, handler) {
 30→	serverRequestHandlers[method] = handler;
 31→	return function off() {
 32→		delete serverRequestHandlers[method];
 33→	};
 34→}
 35→
 36→/**
 37→ * Open a WebSocket, perform the protocol handshake, route RPC responses to
 38→ * `S.pending`, and auto-reconnect on close.
 39→ *
 40→ * @param {Object} opts
 41→ * @param {(frame: object) => void} [opts.onFrame]       — non-RPC frames (events)
 42→ * @param {(hello: object) => void} [opts.onConnected]    — after successful handshake
 43→ * @param {(frame: object) => void} [opts.onHandshakeFailed]
 44→ * @param {(wasConnected: boolean) => void} [opts.onDisconnected]
 45→ * @param {{ factor?: number, max?: number }} [opts.backoff] — default {1.5, 5000}
 46→ */
 47→export function connectWs(opts) {
 48→	lastOpts = opts;
 49→	var backoff = Object.assign({ factor: 1.5, max: 5000 }, opts.backoff);
 50→	var proto = location.protocol === "https:" ? "wss:" : "ws:";
 51→	var ws = new WebSocket(`${proto}//${location.host}/ws/chat`);
 52→	S.setWs(ws);
 53→
 54→	ws.onopen = () => {
 55→		var id = nextId();
 56→		S.pending[id] = (frame) => {
 57→			var hello = frame?.ok && frame.payload;
 58→			if (hello?.type === "hello-ok") {
 59→				S.setConnected(true);
 60→				S.setReconnectDelay(1000);
 61→				if (opts.onConnected) opts.onConnected(hello);
 62→			} else {
 63→				S.setConnected(false);
 64→				if (opts.onHandshakeFailed) opts.onHandshakeFailed(frame);
 65→				else ws.close();
 66→			}
 67→		};
 68→		ws.send(
 69→			JSON.stringify({
 70→				type: "req",
 71→				id: id,
 72→				method: "connect",
 73→				params: {
 74→					protocol: { min: 3, max: 4 },
 75→					client: {
 76→						id: "web-chat-ui",
 77→						version: "0.1.0",
 78→						platform: "browser",
 79→						mode: "operator",
 80→					},
 81→					locale: resolveLocale(),
 82→					timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
 83→				},
 84→			}),
 85→		);
 86→	};
 87→
 88→	ws.onmessage = (evt) => {
 89→		var frame;
 90→		try {
 91→			frame = JSON.parse(evt.data);
 92→		} catch {
 93→			return;
 94→		}
 95→		if (frame?.type === "res" && frame.error) {
 96→			frame.error = localizeRpcError(frame.error);
 97→			// When an RPC response indicates auth failure, trigger the
 98→			// auth-status-changed flow so the UI redirects to login
 99→			// instead of showing stale/broken data. Use a flag to
100→			// avoid dispatching multiple times when several RPCs fail.
101→			if (frame.error.code === "UNAUTHORIZED" && !authRedirectPending) {
102→				authRedirectPending = true;
103→				window.dispatchEvent(new CustomEvent("moltis:auth-status-changed"));
104→			}
105→		}
106→		if (frame.type === "res" && frame.id && S.pending[frame.id]) {
107→			S.pending[frame.id](frame);
108→			delete S.pending[frame.id];
